        entity_frequency[t.subject] = entity_frequency.get(t.subject, 0) + 1
        entity_frequency[t.object] = entity_frequency.get(t.object, 0) + 1

    main_entity = max(entity_frequency, key=entity_frequency.get) if entity_frequency else main_subject

    # Build sentence starting from main entity
