    processed_triples = set()

    # Process triples connected to main entity first
    def get_triple_key(t):
        return (t.subject, t.predicate, t.object)

    # BFS to find connected triples
    queue = [main_entity]
    visited_entities = {main_entity}

    while queue:
        current_entity = queue.pop(0)
        if current_entity in entity_groups:
            for t, phrase in entity_groups[current_entity]:
                triple_key = get_triple_key(t)
                if triple_key not in processed_triples:
                    processed_triples.add(triple_key)
                    result_parts.append((t, phrase))

                    # Add connected entity to queue
                    if t.object not in visited_entities and t.object in entity_groups:
                        queue.append(t.object)
                        visited_entities.add(t.object)

    # Add any remaining unprocessed triples
    for t, phrase in sentence_parts:
        triple_key = get_triple_key(t)
        if triple_key not in processed_triples:
            processed_triples.add(triple_key)
            result_parts.append((t, phrase))

    if not result_parts:
        return ""

    # Build coherent sentence with proper relative clauses
    first_t, first_phrase = result_parts[0]
    result = first_phrase
    mentioned_entities = {first_t.subject, first_t.object}

    for i in range(1, len(result_parts)):
        t, phrase = result_parts[i]

        # Determine how to connect this triple
        subject_connected = t.subject in mentioned_entities
        object_connected = t.object in mentioned_entities

        if subject_connected and t.subject == first_t.subject:
            # Same subject, add as additional clause
            if " is " in phrase:
                parts = phrase.split(" is ", 1)
                result = result + " and is " + parts[1]
            elif " competes in " in phrase:
                parts = phrase.split(" competes in ", 1)
                result = result + " and competes in " + parts[1]
            elif " plays at " in phrase:
                parts = phrase.split(" plays at ", 1)
                result = result + " and plays at " + parts[1]
            else:
                result = result + " and " + phrase
        elif subject_connected:
            # Different subject but connected, use relative clause
            if is_person(t.object):
                pronoun = "who"
            else:
                pronoun = "which"
            result = result + ", " + pronoun + " " + phrase
        elif object_connected:
            # Object is connected, reference it
            if is_person(t.subject):
                pronoun = "who"
            else:
                pronoun = "which"
            result = result + ", " + pronoun + " is " + phrase
        else:
            # No connection, use conjunction
            if i == len(result_parts) - 1:
                result = result + ", and " + phrase
            else:
                result = result + ", " + phrase

        mentioned_entities.add(t.subject)
        mentioned_entities.add(t.object)

    return result + "."

